it('should always send notifications via direct calls', async () => {
  // Even without EventBus listeners, notifications are sent
  // because OrderService calls NotificationService directly
  const isolatedBus = new EventBus();
  const isolatedNotifications = new NotificationService();
  const isolatedOrderService = new OrderService(
    orderRepo,
    userRepo,
    isolatedNotifications,
    isolatedBus,
  );

  await isolatedOrderService.createOrder({
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
    ],
  });

  // Direct calls always work — no listener registration needed
  expect(isolatedNotifications.getNotifications()).toHaveLength(1);
});

parameters.new_string:
it('should not send notifications without EventBus registration', async () => {
  // Without registering event handlers, no notifications are sent —
  // this confirms notifications flow through events, not direct calls
  const isolatedBus = new EventBus();
  const isolatedNotifications = new NotificationService();
  // Intentionally NOT calling isolatedNotifications.registerEventHandlers()
  const isolatedOrderService = new OrderService(
    orderRepo,
    userRepo,
    isolatedBus,
  );

  await isolatedOrderService.createOrder({
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
    ],
  });

  // No handlers registered — no notifications sent
  expect(isolatedNotifications.getNotifications()).toHaveLength(0);
});

